import './App.css';
import axios from 'axios'; // ✅ ADD THIS
import { BrowserRouter, Routes, Route, Link, NavLink, useLocation } from 'react-router-dom';
import { useEffect, useState } from 'react';
import Getproducts from './components/Home';
import Signup from './components/Signup';
import Signin from './components/Signin';
import Notfound from './components/Notfound';
import 'bootstrap/dist/css/bootstrap.min.css';
import Makepayment from './components/Makepayment';
import Rooms from './components/Rooms';
import RoomDetails from './components/RoomDetails';
import Dining from './components/Dining';
import Bookings from './components/Bookings';
import Contactus from './components/Contactus';
import EventInquiry from './components/EventInquiry';

// ✅ GLOBAL AXIOS CONFIG (VERY IMPORTANT)
axios.defaults.withCredentials = true;

function AppLayout() {
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);
  const isHomePage = location.pathname === '/';

  useEffect(() => {
    setMenuOpen(false);
  }, [location.pathname, location.hash]);

  useEffect(() => {
    window.scrollTo({
      top: 0,
      left: 0,
      behavior: 'auto',
    });
  }, [location.key]);

  return (
    <div className="App">
      <header className={`site-header ${isHomePage ? 'site-header--home' : ''}`}>
        <div className="site-header__inner">
          <Link to="/" className="site-brand">
            <span className="site-brand__mark">EH</span>
            <span className="site-brand__text">
              <strong>ELITEHOTELS</strong>
              <small>Hotel & Restaurant</small>
            </span>
          </Link>

          <button
            type="button"
            className={`site-nav__toggle ${menuOpen ? 'is-open' : ''}`}
            onClick={() => setMenuOpen((open) => !open)}
          >
            <span></span>
            <span></span>
            <span></span>
          </button>

          <nav className={`site-nav ${menuOpen ? 'is-open' : ''}`}>
            <Link to="/rooms">Rooms</Link>
            <Link to="/dining">Dining</Link>
            <Link to="/bookings">Bookings</Link>
            <Link to="/contactus">Contact Us</Link>
            <NavLink to="/signin">Sign In</NavLink>
            <NavLink to="/signup">Sign Up</NavLink>
          </nav>
        </div>
      </header>

      <Routes>
        <Route path="/" element={<Getproducts />} />
        <Route path="/signin" element={<Signin />} />
        <Route path="/signup" element={<Signup />} />
        <Route path="/rooms" element={<Rooms />} />
        <Route path="/rooms/:roomSlug" element={<RoomDetails />} />
        <Route path="/dining" element={<Dining />} />
        <Route path="/bookings" element={<Bookings />} />
        <Route path="/contactus" element={<Contactus />} />
        <Route path="/events" element={<EventInquiry />} />
        <Route path="/makepayment" element={<Makepayment />} />
        <Route path="*" element={<Notfound />} />
      </Routes>

      <footer className="site-footer">
        <div className="site-footer__inner">
          <div>
            <Link to="/">ELITEHOTELS</Link>
            <p>Elegant rooms and dining experience.</p>
          </div>

          <div>
            <h4>Links</h4>
            <Link to="/rooms">Rooms</Link>
            <Link to="/dining">Dining</Link>
            <Link to="/bookings">Bookings</Link>
          </div>

          <div>
            <h4>Contact</h4>
            <p>Westlands, Nairobi</p>
            <p>+254 700 123 456</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <AppLayout />
    </BrowserRouter>
  );
}

export default App;
